SELECT id, warehouse_code as "warehouseCode", warehouse_name as "warehouseName", warehouse_type as "warehouseType", city, state, pincode, country, contact_phone as "contactPhone", contact_email as "contactEmail", manager_id as "managerId", max_capacity_units as "maxCapacityUnits", current_utilization_pct as "currentUtilizationPct", is_active as "isActive", is_returns_center as "isReturnsCenter", created_time as "createdTime" FROM warehouses
AND warehouse_code = #{warehouseCode} AND warehouse_name LIKE CONCAT('%', #{warehouseName}, '%') AND warehouse_type = #{warehouseType} AND city = #{city} AND state = #{state} AND pincode = #{pincode} AND is_active = CAST(#{isActive} AS boolean)
${orderby} ${pagination}

SELECT count(*) FROM warehouses

    AND warehouse_code = #{warehouseCode}
    AND warehouse_name LIKE CONCAT('%', #{warehouseName}, '%')
    AND warehouse_type = #{warehouseType}
    AND city = #{city}
    AND state = #{state}
    AND pincode = #{pincode}
    AND is_active = CAST(#{isActive} AS boolean)

SELECT id, warehouse_id as "warehouseId", location_code as "locationCode", zone, aisle, shelf, bin, location_type as "locationType", capacity_units as "capacityUnits", current_units as "currentUnits", is_active as "isActive" FROM warehouse_locations
AND warehouse_id = #{warehouseId} AND location_type = #{locationType} AND zone = #{zone} AND is_active = CAST(#{isActive} AS boolean)
${orderby} ${pagination}

SELECT count(*) FROM warehouse_locations

    AND warehouse_id = #{warehouseId}
    AND location_type = #{locationType}
    AND zone = #{zone}
    AND is_active = CAST(#{isActive} AS boolean)
